import type { HTMLElementType } from 'react';

export type PrimitiveType = boolean | number | string;

export type I18nBaseProps = {
  text: string;

  /**
   * Wrap the rendered text in a custom HTML element.
   *
   * When using `values` or `components` props, by default no wrapper is used, returning an array of React elements. When using the `tags` prop, wrapper is a `div` element by default.
   *
   * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#settings | Documentation}
   * @example
   * i18n.jsx.gettext('My awesome wording', { wrapper: 'p' })
   * // <p>My awesome wording</p>
   */
  wrapper?: HTMLElementType;

  /**
   * Add a custom class name to the wrapper element. Requires `wrapper` to be set.
   *
   * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#settings | Documentation}
   * @example
   * i18n.jsx.gettext('My awesome wording', { wrapper: 'p', className: 'my-class' })
   * // <p class="my-class">My awesome wording</p>
   */
  className?: string;
};
